+// getTickInterval returns the appropriate tick interval based on activity state
+func (m Model) getTickInterval() time.Duration {
+	baseTick := m.baseTick
+	if baseTick == 0 {
+		baseTick = 100 * time.Millisecond
+	}
+	idleTick := m.idleTick
+	if idleTick == 0 {
+		idleTick = 500 * time.Millisecond
+	}
+
+	switch m.activityState {
+	case StateIdle:
+		return idleTick
+	default:
+		return baseTick
+	}
+}
